import React, { useState } from 'react';

const Taskbar = ({ handleMouseEnter, handleMouseLeave, handleClick, taskbarApps }) => {
  const [windows, setWindows] = useState([]);

  const openWindow = (appName) => {
    const newWindow = {
      name: appName,
      id: new Date().getTime(),
    };
    setWindows([...windows, newWindow]);
  };

  const closeWindow = (id) => {
    const updatedWindows = windows.filter((window) => window.id !== id);
    setWindows(updatedWindows);
  };

  return (
    <>
      <div className="taskbar">
        <div className="taskbar-apps">
          {taskbarApps.map((app) => (
            <div
              key={app.id}
              className="taskbar-app"
              onMouseEnter={handleMouseEnter}
              onMouseLeave={handleMouseLeave}
              onClick={() => {
                handleClick(app.name);
                openWindow(app.name);
              }}
            >
              <div className="taskbar-app-icon">{app.name}</div>
              <div className="taskbar-app-text">{app.name}</div>
            </div>
          ))}
        </div>
        {windows.map((window) => (
          <div key={window.id} className="taskbar-window">
            <span>{window.name}</span>
            <button className="window-close" onClick={() => closeWindow(window.id)}>
              X
            </button>
          </div>
        ))}
      </div>
    </>
  );
};

export default Taskbar;
